    private static long power(long base, long exp) {
        long res = 1;
        base %= MOD;
        while (exp > 0) {
            if (exp % 2 == 1) {
                res = (res * base) % MOD;
            }
            base = (base * base) % MOD;
            exp /= 2;
        }
        return res;
    }

    // Modular inverse using Fermat's Little Theorem: a^(MOD-2) % MOD
    private static long modInverse(long n) {
        return power(n, MOD - 2);
    }

    // Precompute factorials and inverse factorials up to maxN
    private static void precompute(int maxN) {
        fact = new long[maxN + 1];
        invFact = new long[maxN + 1];
        fact[0] = 1;
        for (int i = 1; i <= maxN; i++) {
            fact[i] = (fact[i - 1] * i) % MOD;
        }
        invFact[maxN] = modInverse(fact[maxN]);
        for (int i = maxN - 1; i >= 0; i--) {
            invFact[i] = (invFact[i + 1] * (i + 1)) % MOD;
        }
    }

    // Combination function nCk % MOD
    private static long nCr(int n, int r) {
        if (r < 0 || r > n) {
            return 0;
        }
        if (n < 0) {
            return 0;
