        // For this self-contained requirement, we check and precompute if necessary.
        // Since N <= 10^5, we can precompute up to 100000 safely.
        if (fact == null || fact.length <= n) {
             precompute(n);
        }


        // L: number of people to the left (indices 0 to pos-1)
        int L = pos;
        // R: number of people to the right (indices pos+1 to n-1)
        int R = n - 1 - pos;

        long totalOthersWays = 0;

